api.post('/cash-sessions/open',asyncRoute(async(req,res)=>{ const d=z.object({outletId:z.string(),openingCash:z.coerce.number().nonnegative()}).parse(req.body);assertOutlet(req,d.outletId);if(await prisma.cashSession.findFirst({where:{cashierId:req.user!.id,status:'OPEN'}}))throw new ApiError(409,'Masih ada shift yang aktif');res.status(201).json(await prisma.cashSession.create({data:{...d,cashierId:req.user!.id},include:{outlet:true}})); }));
