async function requireActiveShift(req:any,outletId:string,cashSessionId?:string){
  assertOutlet(req,outletId);
  const active=await prisma.cashSession.findFirst({where:{cashierId:req.user!.id,outletId,status:'OPEN'}});
  if(!active)throw new ApiError(400,'Shift belum dibuka. Silakan buka kasir terlebih dahulu.');
  if(cashSessionId&&cashSessionId!==active.id&&!cashSessionId.startsWith('local_'))throw new ApiError(400,'Shift aktif tidak sesuai dengan transaksi.');
  return active;
}
api.post('/cash-sessions/:id/close',asyncRoute(async(req,res)=>{const session=await prisma.cashSession.findFirst({where:{id:String(req.params.id),cashierId:req.user!.id,status:'OPEN'},include:{sales:true,expenses:{where:{status:'ACTIVE'},include:{categoryRef:true},orderBy:{createdAt:'asc'}}}});if(!session)throw new ApiError(404,'Shift aktif tidak ditemukan');const cashSales=session.sales.filter(s=>s.status==='PAID'&&s.paymentMethod==='CASH').reduce((n,s)=>n+Number(s.grandTotal),0);const cashRefund=0;const cashDrawerExpenses=session.expenses.filter(e=>e.paymentSource==='CASH_DRAWER').reduce((n,e)=>n+Number(e.amount),0);const expected=money(Number(session.openingCash)+cashSales-cashRefund-cashDrawerExpenses);const actual=z.object({closingCashActual:z.coerce.number().nonnegative()}).parse(req.body).closingCashActual;const updated=await prisma.cashSession.update({where:{id:session.id},data:{status:'CLOSED',closedAt:new Date(),expectedCash:expected,closingCashActual:actual,variance:money(actual-expected)},include:{outlet:true,cashier:{select:{name:true}},expenses:{where:{status:'ACTIVE'},include:{categoryRef:true},orderBy:{createdAt:'asc'}}}});res.json({...updated,cashSales:money(cashSales),cashRefund:money(cashRefund),cashDrawerExpenses:money(cashDrawerExpenses),expenseDetails:updated.expenses});}));

